insert into movement_patterns (key, label, category, blurb, sort) values
 ('trek_vert', 'Verticaal trekken', 'kracht', 'Van dead hang naar pull-up naar one-arm: de sterkste zichtbare trekladder.', 1),
 ('trek_hor', 'Horizontaal trekken', 'kracht', 'Rijen die je rug dik maken en je houding rechttrekken.', 2),
 ('duw_vert', 'Verticaal duwen', 'kracht', 'Dips: de snelste winst voor borst, schouders en triceps.', 3),
 ('duw_hor', 'Horizontaal duwen', 'kracht', 'Push-ups van incline tot one-arm: duwkracht overal.', 4),
 ('been_knie', 'Benen — knie-dominant', 'kracht', 'Squat-lijn naar de pistol: kracht en balans op één been.', 5),
 ('been_heup', 'Benen — heup-dominant', 'kracht', 'Bilspieren en hamstrings: de motor achter sprinten en tillen.', 6),
 ('core', 'Core', 'kracht', 'Van dead bug naar L-sit: een romp die kracht doorgeeft.', 7),
 ('plyo', 'Elasticiteit', 'elasticiteit', 'Explosieve veerkracht — laag volume, altijd fris, steunt je hardlopen.', 8),
 ('mobiliteit', 'Mobiliteit', 'mobiliteit', 'De korte dagelijkse routine die je soepel en blessurevrij houdt.', 9)
insert into session_templates (key, label, blurb) values
 ('kracht_a', 'Kracht A — trek-nadruk', 'Full-body met de nadruk op trekken. Trek verticaal, duw horizontaal, benen en core.'),
 ('kracht_b', 'Kracht B — duw-nadruk', 'Full-body met de nadruk op duwen. Dips, rijen, heupen en core.')
insert into session_template_slots (template_id, sort, slot_type, pattern_id, sets, note)
insert into session_template_slots (template_id, sort, slot_type, pattern_id, sets, note)
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='trek_vert'), 1, 'tv1_dead_hang', 'Passieve dead hang', 'Je bouwt greep en schouderstabiliteit door simpelweg te hangen.', '{"Pak de stang iets breder dan schouderbreedte, duimen eromheen.","Laat je armen volledig strekken en je schouders rustig omhoog zakken.","Voeten los van de grond, benen stil."}'::text[], '{"Hang ontspannen en laat je greep en romp het werk doen.","Houd je lichaam stil: geen zwaaien.","Bouw de tijd op tot je 45 seconden schoon hangt."}'::text[], 'Adem rustig door; span je greep aan op elke uitademing.', '{"Zwaaien met de benen: kruis je enkels en span je billen aan.","Losse greep die te snel opgeeft: knijp de stang actief.","Schouders in paniek optrekken: laat ze eerst rustig zakken."}'::text[], 'hold', null, null, 45, 60, false, null, null, 'bij 45s schoon hangen', null, 'tv2_scapula_pull', 'rekstok', '{onderarmen,grip,schouders}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='trek_vert'), 2, 'tv2_scapula_pull', 'Scapula pull-up', 'De eerste echte trekbeweging: alleen je schouderbladen doen het werk.', '{"Hang met gestrekte armen aan de stang, greep schouderbreed.","Romp gespannen, benen stil."}'::text[], '{"Zonder je ellebogen te buigen: trek je schouderbladen omlaag en naar elkaar.","Je lichaam komt een paar centimeter omhoog.","Zak gecontroleerd terug naar de volle hang."}'::text[], 'Adem uit terwijl je je schouders naar beneden trekt.', '{"Ellebogen buigen: houd de armen recht, dit is puur scapula.","Schokkerig trekken: maak het traag en bewust.","Geen volle hang tussen reps: strek elke keer volledig."}'::text[], '2-1-2', 8, 8, null, 75, false, 8, 3, 'bij 3x8 schoon', 'tv1_dead_hang', 'tv3_negatieve_pullup', 'rekstok', '{rug,schouders,grip}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='trek_vert'), 3, 'tv3_negatieve_pullup', 'Negatieve pull-up', 'Je bouwt trekkracht door alleen het zakken te beheersen.', '{"Spring of stap naar de stang met je kin al boven de stang.","Handen iets breder dan schouders, duimen eromheen.","Span je romp en knijp je billen: een rechte lijn, geen bungelen."}'::text[], '{"Laat jezelf in ongeveer 4 seconden gecontroleerd zakken.","Blijf de stang naar je toe trekken terwijl je zakt, vecht tegen de zwaartekracht.","Volledig gestrekte armen onderaan, dan opnieuw opstappen."}'::text[], 'Adem in bovenaan, langzaam uit terwijl je zakt.', '{"Ploffen naar beneden: verlies van de hele prikkel, tel echt tot vier.","Schouders bij de oren: trek ze eerst naar beneden.","Doorzwaaien met de benen: romp en billen aanspannen."}'::text[], '4s zakken', 4, 5, null, 120, false, 5, 4, 'bij 4x5 met 4s zakken', 'tv2_scapula_pull', 'tv4_band_pullup', 'rekstok', '{rug,biceps,grip}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='trek_vert'), 4, 'tv4_band_pullup', 'Band-assisted pull-up', 'De volledige beweging met een band die je onderaan helpt waar je het zwakst bent.', '{"Hang een weerstandsband over de stang en zet er een voet of knie in.","Greep iets breder dan schouders, schouders al naar beneden getrokken."}'::text[], '{"Trek jezelf op tot je kin boven de stang komt.","Zak gecontroleerd terug tot volledig gestrekte armen.","Gebruik de lichtste band waarmee je de volle ROM haalt."}'::text[], 'Adem uit op de weg omhoog, in op de weg omlaag.', '{"Te zware band: kies er een die je alleen onderaan helpt.","Half omhoog: kin moet echt over de stang.","Geen volle hang onderaan: strek elke rep volledig."}'::text[], '2-0-2', 5, 5, null, 120, false, 5, 3, 'bij 3x5 volle ROM', 'tv3_negatieve_pullup', 'tv5_pullup', 'rekstok', '{rug,biceps,grip}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='trek_vert'), 5, 'tv5_pullup', 'Volledige pull-up', 'Het ijkpunt: jezelf strict optrekken tot je kin over de stang.', '{"Volle dode hang, greep iets breder dan schouders.","Trek je schouders naar beneden voor je begint."}'::text[], '{"Trek in een vloeiende beweging tot je kin boven de stang komt.","Zak gecontroleerd terug tot volledig gestrekte armen.","Geen kip of zwaai: strict."}'::text[], 'Adem uit op de weg omhoog, in op de weg omlaag.', '{"Kippen met de heupen: houd je romp stil en strak.","Kin niet over de stang: dat telt niet als volle rep.","Snel laten vallen: beheers ook het zakken."}'::text[], '2-0-1', 5, 8, null, 150, false, 8, 3, 'bij 3x8 strict', 'tv4_band_pullup', 'tv6_gewogen_pullup', 'rekstok', '{rug,biceps,grip}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='trek_vert'), 6, 'tv6_gewogen_pullup', 'Gewogen of archer pull-up', 'Zwaarder of eenzijdiger: de brug naar de one-arm.', '{"Gewogen: hang een gewicht aan een dip-riem of klem het tussen je voeten.","Archer: brede greep, trek naar een hand terwijl de andere arm strekt."}'::text[], '{"Gewogen: strict optrekken tot kin over de stang, gecontroleerd zakken.","Archer: trek je romp naar een kant, de andere arm blijft licht gebogen als steun.","Wissel per set van kant bij de archer."}'::text[], 'Adem uit op de weg omhoog, in op de weg omlaag.', '{"Te veel gewicht ineens: bouw in kleine stappen op.","Archer met een slappe steunarm: houd hem actief.","ROM inleveren voor gewicht: volle rep blijft de standaard."}'::text[], '2-0-1', 3, 5, null, 180, true, 5, 3, 'bij 3x5 gewogen of 3x3 per kant archer', 'tv5_pullup', 'tv7_one_arm', 'rekstok', '{rug,biceps,grip}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='trek_vert'), 7, 'tv7_one_arm', 'One-arm-progressies', 'Het langetermijndoel: trekken op een arm.', '{"Begin met one-arm negatives: zak op een arm van boven naar beneden.","Of gebruik een handdoek/vinger-assist met de andere hand."}'::text[], '{"Zak zo langzaam mogelijk op een arm, romp strak.","Voeg pas kracht toe als je de negatieve volledig beheerst.","Dit is een project van maanden, niet weken."}'::text[], 'Rustig en gecontroleerd ademen door de hele beweging.', '{"Te vroeg forceren: bouw eerst de negatieve op.","Romp laten roteren: houd je schouders vierkant.","Ongeduld: dit is de top van de ladder, respecteer de opbouw."}'::text[], 'zo langzaam mogelijk', 1, 3, null, 180, true, 3, 3, 'lange termijn', 'tv6_gewogen_pullup', null, 'rekstok', '{rug,biceps,grip}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='trek_hor'), 1, 'th1_rechtop_row', 'Rechtop rij', 'De makkelijkste rij: hoe rechter je staat, hoe lichter.', '{"Pak een lage stang of ringen op heuphoogte, greep schouderbreed.","Loop je voeten iets naar voren zodat je licht achterover leunt.","Romp gespannen, een rechte lijn van hielen tot hoofd."}'::text[], '{"Trek eerst je schouderbladen samen, dan pas je ellebogen naar achteren.","Trek je borst naar de stang.","Zak gecontroleerd terug tot gestrekte armen."}'::text[], 'Adem uit op het trekken, in op het zakken.', '{"Alleen met de armen trekken: start vanuit de schouderbladen.","Doorzakkende heupen: span je billen en romp aan.","Halve reps: borst moet echt naar de stang."}'::text[], '2-1-2', 12, 12, null, 75, false, 12, 3, 'bij 3x12 schoon', null, 'th2_australian_row', 'rekstok', '{rug,biceps,achterste-schouder}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='trek_hor'), 2, 'th2_australian_row', 'Australian row', 'Horizontaler onder de stang: nu doet je rug echt werk.', '{"Leg een stang op heuphoogte, ga eronder liggen en pak hem schouderbreed.","Hielen op de grond, lichaam een rechte plank."}'::text[], '{"Trek je borst naar de stang, ellebogen langs je lijf.","Knijp je schouderbladen samen bovenaan.","Zak gecontroleerd tot gestrekte armen."}'::text[], 'Adem uit op het trekken, in op het zakken.', '{"Heupen laten zakken: houd een strakke plank.","Kin reiken in plaats van borst: laat je borst de stang raken.","Te snel zakken: beheers de negatieve."}'::text[], '2-1-2', 10, 10, null, 90, false, 10, 3, 'bij 3x10 schoon', 'th1_rechtop_row', 'th3_feet_up_row', 'rekstok', '{rug,biceps,achterste-schouder}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='trek_hor'), 3, 'th3_feet_up_row', 'Voeten verhoogd row', 'Voeten omhoog maakt de hefboom zwaarder en de rug sterker.', '{"Zelfde stangpositie als de Australian row.","Leg je voeten op een bank of verhoging zodat je bijna horizontaal hangt."}'::text[], '{"Trek je borst naar de stang met samengeknepen schouderbladen.","Houd je lichaam kaarsrecht van schouders tot hielen.","Zak gecontroleerd terug."}'::text[], 'Adem uit op het trekken, in op het zakken.', '{"Doorhangende heupen door de zwaardere hefboom: extra romp aanspannen.","Ellebogen wijd: houd ze dichter langs je lijf.","ROM inleveren: raak de stang elke rep."}'::text[], '2-1-2', 8, 8, null, 90, false, 8, 3, 'bij 3x8 schoon', 'th2_australian_row', 'th4_front_lever', 'rekstok', '{rug,biceps,core}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='trek_hor'), 4, 'th4_front_lever', 'Tuck front lever row', 'De weg naar de front lever: horizontaal trekken met je hele lichaam los.', '{"Hang aan de stang en trek je knieen in tot een strakke tuck.","Romp maximaal gespannen, heupen op stanghoogte."}'::text[], '{"Trek in tuck-positie je lichaam naar de stang toe.","Houd je heupen hoog en je rug vlak.","Strek de tuck geleidelijk verder open naarmate je sterker wordt."}'::text[], 'Rustig doorademen; niet je adem inhouden.', '{"Heupen laten zakken: houd ze op stanghoogte.","Ronde rug: houd je borst open en schouderbladen vast.","Te vroeg openstrekken: bouw de tuck stap voor stap open."}'::text[], 'gecontroleerd', 5, 8, null, 120, false, 8, 3, 'lange termijn', 'th3_feet_up_row', null, 'rekstok', '{rug,core,schouders}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='duw_vert'), 1, 'dv1_support_hold', 'Support hold', 'Rechte armen op de stang: de basis voor elke dip.', '{"Plaats je handen op een dip-stang of parallelle stangen.","Duw jezelf omhoog tot volledig gestrekte armen.","Schouders laag weg van je oren, borst iets voorover, romp strak."}'::text[], '{"Houd de positie stil, armen recht.","Knijp je schouderbladen licht naar beneden en vast.","Bouw op tot 30 seconden schoon."}'::text[], 'Rustig doorademen; blijf je romp aanspannen.', '{"Schouders bij de oren: duw jezelf actief weg van de stang.","Doorzakken in de armen: houd ze volledig gestrekt.","Bungelende benen: kruis je enkels en span je billen."}'::text[], 'hold', null, null, 30, 60, false, null, null, 'bij 30s schoon', null, 'dv2_negatieve_dip', 'dip', '{borst,triceps,schouders}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='duw_vert'), 2, 'dv2_negatieve_dip', 'Negatieve dip', 'Bouw dipkracht door alleen het zakken te beheersen.', '{"Start in de support hold met gestrekte armen.","Schouders laag, borst iets voorover."}'::text[], '{"Zak in ongeveer 4 seconden gecontroleerd tot je bovenarmen horizontaal zijn.","Stap of spring terug omhoog naar de start.","Blijf de hele weg controle houden."}'::text[], 'Adem in terwijl je zakt.', '{"Snel laten zakken: tel echt tot vier.","Te diep bij pijnlijke schouders: stop bij horizontaal.","Schouders optrekken: houd ze laag."}'::text[], '4s zakken', 5, 5, null, 120, false, 5, 3, 'bij 3x5 met 4s zakken', 'dv1_support_hold', 'dv3_dip', 'dip', '{borst,triceps,schouders}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='duw_vert'), 3, 'dv3_dip', 'Volledige dip', 'De snelste er-goed-uitzien-winst: borst, schouders, triceps.', '{"Rechte armen op de stang, schouders laag, borst iets voorover.","Benen licht gebogen of gekruist, romp gespannen."}'::text[], '{"Zak tot je bovenarmen ongeveer horizontaal zijn.","Duw krachtig terug omhoog tot rechte armen, zonder te kantelen."}'::text[], 'In op de weg omlaag, uit op de weg omhoog.', '{"Te diep zakken met pijnlijke schouders: stop bij horizontaal.","Schouders optrekken: houd ze laag, weg van je oren.","Half-reps: volledige strekking bovenaan telt pas."}'::text[], '3-0-1', 6, 8, null, 120, false, 8, 3, 'bij 3x8 volle ROM', 'dv2_negatieve_dip', 'dv4_gewogen_dip', 'dip', '{borst,triceps,schouders}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='duw_vert'), 4, 'dv4_gewogen_dip', 'Gewogen of ring dip', 'Extra weerstand of instabiliteit: de top van de duwladder.', '{"Gewogen: hang gewicht aan een dip-riem.","Ringen: dips op gymringen voor extra stabiliteitseis."}'::text[], '{"Zak gecontroleerd tot bovenarmen horizontaal.","Duw krachtig omhoog tot volledige strekking.","Ringen: houd ze dicht langs je lijf, draai je handen bovenaan licht uit."}'::text[], 'In op de weg omlaag, uit op de weg omhoog.', '{"Te veel gewicht: bouw in kleine stappen op.","Ringen die wegdraaien: knijp ze actief tegen je lijf.","ROM inleveren: volle diepte blijft de standaard."}'::text[], '3-0-1', 5, 8, null, 150, false, 8, 3, 'lange termijn', 'dv3_dip', null, 'dip', '{borst,triceps,schouders}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='duw_hor'), 1, 'dh1_incline_pushup', 'Incline push-up', 'Handen verhoogd maakt de push-up lichter zonder in te leveren op vorm.', '{"Zet je handen op een bank, tafel of muur, iets breder dan schouders.","Loop je voeten naar achteren tot een rechte plank.","Span je buik en billen aan."}'::text[], '{"Zak met je borst richting de rand tot je ellebogen ongeveer 90 graden zijn.","Duw krachtig terug tot gestrekte armen.","Hoe lager de verhoging, hoe zwaarder."}'::text[], 'In op de weg omlaag, uit op de weg omhoog.', '{"Doorhangende heupen: houd een strakke plank.","Ellebogen wijd: houd ze rond 45 graden langs je lijf.","Halve reps: borst echt naar de rand."}'::text[], '3-0-1', 12, 12, null, 75, false, 12, 3, 'bij 3x12 schoon', null, 'dh2_pushup', 'verhoging', '{borst,triceps,schouders}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='duw_hor'), 2, 'dh2_pushup', 'Volledige push-up', 'Het klassieke ijkpunt voor duwkracht en rompstabiliteit.', '{"Handen iets breder dan schouderbreed, lichaam een rechte lijn van hoofd tot hielen.","Span je buik en billen aan."}'::text[], '{"Zak gecontroleerd tot je borst net boven de grond is, ellebogen rond 45 graden.","Duw krachtig terug omhoog tot gestrekte armen."}'::text[], 'In op de weg omlaag, uit terwijl je omhoog duwt.', '{"Doorhangende heupen: span buik en billen aan, blijf een plank.","Kin reiken: laat je borst zakken, niet je hoofd.","Ellebogen wijd: houd ze rond 45 graden."}'::text[], '3-0-1', 10, 10, null, 90, false, 10, 3, 'bij 3x10 schoon', 'dh1_incline_pushup', 'dh3_diamond_pushup', 'geen', '{borst,triceps,schouders,core}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='duw_hor'), 3, 'dh3_diamond_pushup', 'Diamond of tempo push-up', 'Handen dichter bij elkaar of trager: meer triceps en spanning.', '{"Diamond: zet je handen onder je borst zodat duimen en wijsvingers een ruit vormen.","Lichaam een strakke rechte lijn."}'::text[], '{"Zak gecontroleerd tot je borst de handen bijna raakt.","Duw krachtig omhoog, ellebogen dicht langs je lijf.","Tempo-variant: zak in 4 seconden voor extra spanning."}'::text[], 'In op de weg omlaag, uit op de weg omhoog.', '{"Ellebogen laten flappen: houd ze dicht langs je lijf.","Heupen omhoog steken: blijf een rechte lijn.","Halve reps: volledige diepte en strekking."}'::text[], '4-0-1', 8, 8, null, 90, false, 8, 3, 'bij 3x8 schoon', 'dh2_pushup', 'dh4_archer_pushup', 'geen', '{triceps,borst,core}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='duw_hor'), 4, 'dh4_archer_pushup', 'Archer push-up', 'Het meeste gewicht op een arm: de brug naar de one-arm push-up.', '{"Brede push-up-positie, een hand recht onder je schouder, de andere ver opzij.","Lichaam een strakke plank."}'::text[], '{"Zak naar de werkende arm terwijl de andere arm strekt en meehelpt als steun.","Duw terug omhoog vanuit de werkende arm.","Wissel per set van kant."}'::text[], 'In op de weg omlaag, uit op de weg omhoog.', '{"Op de steunarm leunen: laat de werkende arm het werk doen.","Romp laten roteren: houd je heupen vierkant.","Te weinig diepte: borst zakt echt naar de werkende hand."}'::text[], '3-0-1', 5, 5, null, 120, true, 5, 3, 'bij 3x5 per kant', 'dh3_diamond_pushup', 'dh5_planche', 'geen', '{borst,triceps,core}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='duw_hor'), 5, 'dh5_planche', 'Pseudo-planche progressie', 'Leunen op je handen met je schouders ver voor je polsen: naar de one-arm en planche.', '{"Push-up-positie met je handen ter hoogte van je heupen, vingers licht naar buiten.","Leun je schouders ver voorbij je handen."}'::text[], '{"Zak en duw terwijl je die voorwaartse lean vasthoudt.","Hoe verder je leunt, hoe zwaarder.","Bouw richting one-arm push-up en planche-holds."}'::text[], 'Rustig doorademen door de hele beweging.', '{"Schouders achter de polsen: leun juist ver naar voren.","Doorhangende heupen: span alles aan.","Te snel: dit is een langzaam kracht-project."}'::text[], 'gecontroleerd', 5, 8, null, 150, false, 8, 3, 'lange termijn', 'dh4_archer_pushup', null, 'geen', '{schouders,borst,core}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='been_knie'), 1, 'bk1_squat', 'Bodyweight squat', 'De basis van elke beenbeweging: diep, hielen plat.', '{"Voeten iets breder dan heupbreed, tenen licht naar buiten.","Romp rechtop, armen voor je uit voor balans."}'::text[], '{"Zak omlaag alsof je op een stoel gaat zitten, gewicht op je hielen.","Ga zo diep als je kunt met platte hielen en rechte rug.","Duw krachtig omhoog via je hielen."}'::text[], 'In op de weg omlaag, uit terwijl je omhoog duwt.', '{"Knieen die naar binnen vallen: duw ze actief naar buiten.","Hielen die loskomen: werk aan enkelmobiliteit, zak minder diep.","Ronde onderrug: houd je borst omhoog."}'::text[], '3-1-1', 15, 15, null, 75, false, 15, 3, 'bij 3x15 diep', null, 'bk2_split_squat', 'geen', '{quadriceps,bilspieren,core}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='been_knie'), 2, 'bk2_split_squat', 'Split squat', 'Een been voor, een achter: de eerste stap naar eenbenige kracht.', '{"Grote stap naar voren, voeten op heupbreedte uit elkaar.","Romp rechtop, gewicht vooral op het voorste been."}'::text[], '{"Zak recht omlaag tot je achterste knie bijna de grond raakt.","Duw via je voorste hiel terug omhoog.","Maak alle reps op een been af, wissel dan."}'::text[], 'In omlaag, uit als je omhoog duwt.', '{"Voorste knie ver voorbij de tenen: stap groter.","Wiebelen: ga langzamer, fixeer je blik.","Op het achterste been leunen: houd het gewicht voor."}'::text[], '2-1-1', 10, 10, null, 90, true, 10, 3, 'bij 3x10 per kant', 'bk1_squat', 'bk3_bulgarian', 'geen', '{quadriceps,bilspieren,balans}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='been_knie'), 3, 'bk3_bulgarian', 'Bulgarian split squat', 'Een been tegelijk: kracht en balans, zonder gewichten.', '{"Achterste voet op een verhoging (bank of trede), grote stap naar voren.","Romp rechtop, voorste voet plat."}'::text[], '{"Zak recht omlaag tot je voorste dij bijna horizontaal is.","Duw via je voorste hiel terug omhoog; achterste been stuurt, voorste werkt."}'::text[], 'In omlaag, uit als je omhoog duwt.', '{"Voorste knie ver voorbij de tenen: stap groter.","Op de achterste voet staan: 80 procent gewicht op het voorste been.","Wiebelen: ga langzamer, fixeer je blik."}'::text[], '2-1-1', 8, 8, null, 90, true, 8, 3, 'bij 3x8 per kant', 'bk2_split_squat', 'bk4_assisted_pistol', 'verhoging', '{quadriceps,bilspieren,balans}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='been_knie'), 4, 'bk4_assisted_pistol', 'Assisted pistol', 'De volle eenbenige squat, met lichte steun waar je hem nodig hebt.', '{"Sta op een been naast een paal, deurpost of met een band als steun.","Andere been gestrekt voor je uit."}'::text[], '{"Zak gecontroleerd tot volledige diepte op een been.","Gebruik de steun zo min mogelijk, alleen voor balans.","Duw via je hiel terug omhoog."}'::text[], 'In omlaag, uit als je omhoog duwt.', '{"Aan de steun hangen: gebruik hem alleen voor balans.","Hiel die loskomt: werk aan enkelmobiliteit.","Doorzakkende knie naar binnen: duw hem naar buiten."}'::text[], '3-1-1', 5, 5, null, 120, true, 5, 3, 'bij 3x5 per kant', 'bk3_bulgarian', 'bk5_pistol', 'geen', '{quadriceps,bilspieren,balans}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='been_knie'), 5, 'bk5_pistol', 'Pistol squat', 'De volledige eenbenige squat, vrij: kracht, balans en mobiliteit in een.', '{"Sta op een been, andere been gestrekt voor je uit.","Armen voor je uit voor balans."}'::text[], '{"Zak gecontroleerd tot je zitvlak bijna je hiel raakt.","Houd je andere been van de grond.","Duw krachtig via je hiel terug omhoog."}'::text[], 'In omlaag, uit als je omhoog duwt.', '{"Omvallen naar achteren: leun je romp iets meer naar voren.","Hiel loskomt: mobiliseer je enkels.","Knie naar binnen: duw hem actief naar buiten."}'::text[], '3-1-1', 3, 5, null, 150, true, 5, 3, 'lange termijn', 'bk4_assisted_pistol', null, 'geen', '{quadriceps,bilspieren,balans}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='been_heup'), 1, 'bh1_glute_bridge', 'Glute bridge', 'Wek je bilspieren die slapen door al dat zitten.', '{"Lig op je rug, knieen gebogen, voeten plat en heupbreed.","Armen langs je lijf, hielen dicht bij je zitvlak."}'::text[], '{"Duw via je hielen je heupen omhoog tot een rechte lijn van knie tot schouder.","Knijp bovenaan je bilspieren hard aan.","Zak gecontroleerd terug."}'::text[], 'Uit op de weg omhoog, in op de weg omlaag.', '{"Met de onderrug omhoog komen: knijp bewust de billen, niet de rug.","Te weinig hoogte: kom tot een volledige heupstrekking.","Voeten te ver weg: houd je hielen dicht bij je zitvlak."}'::text[], '2-1-2', 15, 15, null, 60, false, 15, 3, 'bij 3x15 met harde kneep', null, 'bh2_single_leg_bridge', 'geen', '{bilspieren,hamstrings,core}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='been_heup'), 2, 'bh2_single_leg_bridge', 'Single-leg glute bridge', 'Een been tegelijk: dubbel zo zwaar voor je bilspier.', '{"Lig op je rug, een voet plat, het andere been gestrekt omhoog.","Armen langs je lijf voor stabiliteit."}'::text[], '{"Duw via de hiel van het steunbeen je heupen omhoog.","Houd je bekken vlak, laat het niet naar een kant zakken.","Maak alle reps op een been af, wissel dan."}'::text[], 'Uit op de weg omhoog, in op de weg omlaag.', '{"Bekken dat wegzakt: houd beide heupen op gelijke hoogte.","Met de rug tillen: knijp de bilspier van het steunbeen.","Te weinig hoogte: volledige heupstrekking."}'::text[], '2-1-2', 10, 10, null, 75, true, 10, 3, 'bij 3x10 per kant', 'bh1_glute_bridge', 'bh3_single_leg_rdl', 'geen', '{bilspieren,hamstrings,core}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='been_heup'), 3, 'bh3_single_leg_rdl', 'Single-leg RDL', 'Scharnieren op een been: hamstrings, bilspier en balans in een.', '{"Sta op een been, lichte kniebuiging.","Andere been strekt naar achteren als tegenwicht."}'::text[], '{"Scharnier vanuit je heup naar voren met een rechte rug.","Laat je romp en achterste been een rechte lijn vormen tot ongeveer horizontaal.","Kom terug omhoog door je heup naar voren te duwen."}'::text[], 'In terwijl je scharniert, uit als je omhoog komt.', '{"Ronde rug: houd hem lang, scharnier vanuit de heup.","Roterend bekken: houd je heupen vierkant naar de grond.","Balans verliezen: ga langzamer, fixeer je blik."}'::text[], '3-1-1', 10, 10, null, 90, true, 10, 3, 'bij 3x10 per kant', 'bh2_single_leg_bridge', 'bh4_nordic_negatives', 'geen', '{hamstrings,bilspieren,balans}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='been_heup'), 4, 'bh4_nordic_negatives', 'Nordic curl negatives', 'Het zwaarste voor je hamstrings: alleen het zakken beheersen.', '{"Kniel rechtop, laat iemand je enkels vasthouden of klem ze onder iets zwaars.","Romp en heupen gestrekt, een rechte lijn van knie tot hoofd."}'::text[], '{"Laat jezelf zo langzaam mogelijk naar voren zakken.","Houd je heupen gestrekt: knik niet in je heup.","Vang jezelf met je handen op en duw terug omhoog."}'::text[], 'Rustig doorademen; span je hamstrings maximaal aan.', '{"Knikken in de heup: houd een rechte lijn van knie tot hoofd.","Te snel vallen: rem elke centimeter af.","Handen te laat: houd ze klaar om op te vangen."}'::text[], 'zo langzaam mogelijk', 3, 6, null, 120, false, 6, 3, 'lange termijn', 'bh3_single_leg_rdl', null, 'geen', '{hamstrings,bilspieren}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='core'), 1, 'co1_dead_bug', 'Dead bug', 'Leer je romp spannen terwijl je armen en benen bewegen: rugbescherming.', '{"Lig op je rug, armen recht omhoog, knieen boven je heupen in 90 graden.","Druk je onderrug in de grond."}'::text[], '{"Strek langzaam je rechterarm naar achteren en je linkerbeen naar voren.","Houd je onderrug tegen de grond gedrukt.","Terug naar het midden en wissel van kant."}'::text[], 'Adem uit terwijl arm en been strekken, in bij het terugkomen.', '{"Onderrug laten hollen: druk je lage rug bewust in de grond.","Te snel: langzaam en gecontroleerd doet het werk.","Adem inhouden: blijf rustig doorademen."}'::text[], '3-0-3', 10, 10, null, 60, true, 10, 3, 'bij 3x10 per kant', null, 'co2_hollow_hold', 'geen', '{core,heupbuigers}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='core'), 2, 'co2_hollow_hold', 'Hollow hold', 'De basispositie van alle gymnastiek: een gespannen, holle romp.', '{"Op je rug, onderrug in de grond gedrukt (geen holte).","Armen langs de oren, benen gestrekt."}'::text[], '{"Til schouderbladen en benen net van de grond.","Houd de onderrug tegen de grond, daar zit de oefening.","Vorm een ondiepe banaan en houd vast."}'::text[], 'Rustig doorademen; niet je adem inhouden.', '{"Onderrug komt omhoog: benen hoger of knieen licht buigen (regressie).","Nek meetrekken: kin licht in, blik omhoog.","Vasthouden op adem: blijf rustig ademen."}'::text[], 'hold', null, null, 30, 60, false, 30, 3, 'bij 3x30s met vlakke onderrug', 'co1_dead_bug', 'co3_hollow_rocks', 'geen', '{core,heupbuigers}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='core'), 3, 'co3_hollow_rocks', 'Hollow rocks', 'De hollow hold in beweging: dynamische rompspanning.', '{"Neem de hollow-positie aan: schouderbladen en benen net los, onderrug plat.","Span je hele romp aan als een strakke boog."}'::text[], '{"Schommel als een boog heen en weer vanuit je schouders naar je heupen.","Houd de banaanvorm de hele tijd vast.","De beweging komt van je romp, niet van zwaaien met je ledematen."}'::text[], 'Rustig doorademen op het ritme van het schommelen.', '{"Vorm verliezen tijdens het rocken: blijf de banaan vasthouden.","Onderrug loskomt: verklein de beweging.","Met de armen zwaaien: laat je romp schommelen."}'::text[], 'ritmisch', 12, 12, null, 60, false, 12, 3, 'bij 3x12 met strakke vorm', 'co2_hollow_hold', 'co4_hanging_knee_raise', 'geen', '{core,heupbuigers}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='core'), 4, 'co4_hanging_knee_raise', 'Hanging knee raise', 'Hangende core: je leert je bekken kantelen tegen de zwaartekracht in.', '{"Hang aan de stang, schouders actief naar beneden getrokken.","Benen gestrekt, lichaam stil."}'::text[], '{"Til je knieen op tot voorbij 90 graden en kantel je bekken licht.","Rol je onderrug bij de top mee, til niet alleen met de heupbuigers.","Zak gecontroleerd terug, geen zwaai."}'::text[], 'Uit terwijl je optilt, in terwijl je zakt.', '{"Zwaaien om omhoog te komen: begin vanuit stilstand.","Alleen de heupbuigers: kantel je bekken mee.","Schouders passief: houd ze actief naar beneden."}'::text[], '2-0-2', 10, 10, null, 75, false, 10, 3, 'bij 3x10 zonder zwaai', 'co3_hollow_rocks', 'co5_hanging_leg_raise', 'rekstok', '{core,heupbuigers,grip}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='core'), 5, 'co5_hanging_leg_raise', 'Hanging leg raise', 'Gestrekte benen omhoog: de zware versie van de hangende core.', '{"Hang aan de stang, schouders actief laag.","Benen volledig gestrekt."}'::text[], '{"Til je gestrekte benen op tot ze horizontaal of hoger zijn.","Kantel je bekken mee bij de top.","Zak langzaam en beheerst terug zonder te zwaaien."}'::text[], 'Uit terwijl je optilt, in terwijl je zakt.', '{"Knieen buigen om vals te spelen: houd de benen recht.","Zwaaien: begin vanuit stilstand, zak gecontroleerd.","Onderrug laten hollen: kantel je bekken."}'::text[], '2-0-2', 8, 8, null, 90, false, 8, 3, 'bij 3x8 met rechte benen', 'co4_hanging_knee_raise', 'co6_l_sit', 'rekstok', '{core,heupbuigers,grip}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='core'), 6, 'co6_l_sit', 'Toes-to-bar / L-sit', 'De top van de core-ladder: volledige controle over een hangend of gesteund lichaam.', '{"Toes-to-bar: hang aan de stang. L-sit: steun op parallel of de grond, armen recht.","Romp maximaal gespannen."}'::text[], '{"Toes-to-bar: breng je gestrekte tenen helemaal naar de stang.","L-sit: til je gestrekte benen tot horizontaal en houd vast.","Bouw de houdtijd of het aantal reps geleidelijk op."}'::text[], 'Rustig doorademen; span je romp continu aan.', '{"Knieen buigen: houd de benen recht (of tuck als regressie).","Schouders optrekken bij de L-sit: duw jezelf laag weg.","Zwaaien bij toes-to-bar: strict vanuit stilstand."}'::text[], 'gecontroleerd', 5, 8, null, 120, false, 8, 3, 'lange termijn', 'co5_hanging_leg_raise', null, 'rekstok', '{core,heupbuigers,grip}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='plyo'), 1, 'pl1_pogo_hops', 'Pogo hops', 'Stijve enkels, korte grondcontacten: je leert veren als een bal.', '{"Sta rechtop, voeten heupbreed, lichte spanning in je enkels.","Armen ontspannen mee."}'::text[], '{"Spring laag en snel op de bal van je voeten, knieen bijna gestrekt.","Houd je grondcontact zo kort mogelijk, als een pogostick.","Kwaliteit boven hoogte: blijf fris."}'::text[], 'Rustig en ritmisch doorademen.', '{"Diep door de knieen zakken: houd ze bijna gestrekt, veer uit de enkels.","Lang op de grond blijven: minimaliseer de contacttijd.","Doorgaan bij vermoeidheid: stop zodra het traag wordt."}'::text[], 'snel en stijf', null, null, 20, 60, false, 20, 3, 'bij 3x20s schoon en snel', null, 'pl2_lateral_hops', 'geen', '{kuiten,enkels,elasticiteit}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='plyo'), 2, 'pl2_lateral_hops', 'Line of laterale hops', 'Zijwaartse veerkracht: stabiliteit en pees-stijfheid opzij.', '{"Leg een lijn of laag voorwerp op de grond.","Sta ernaast op de bal van je voeten."}'::text[], '{"Spring snel zijwaarts heen en weer over de lijn.","Korte grondcontacten, stijve enkels.","Blijf licht en gecontroleerd."}'::text[], 'Rustig en ritmisch doorademen.', '{"Zwaar landen: land zacht op de voorvoet.","Uit balans: begin lager en langzamer.","Te lang doorgaan: stop bij kwaliteitsverlies."}'::text[], 'snel en licht', null, null, 20, 60, false, 20, 3, 'bij 3x20s gecontroleerd', 'pl1_pogo_hops', 'pl3_broad_jump', 'geen', '{kuiten,enkels,elasticiteit}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='plyo'), 3, 'pl3_broad_jump', 'Broad jump', 'Maximale horizontale explosie, weinig reps: pure kracht-output.', '{"Sta met voeten heupbreed, licht door de knieen.","Armen naar achteren geladen."}'::text[], '{"Zwaai je armen naar voren en spring zo ver mogelijk naar voren.","Land zacht en gecontroleerd op beide voeten.","Reset volledig tussen elke sprong."}'::text[], 'Adem in bij het laden, krachtig uit bij de sprong.', '{"Reps aan elkaar rijgen: elke sprong is een maximale, verse poging.","Hard landen: zak zacht door de knieen.","Vermoeid door hoog volume: houd het bij een paar kwaliteitssprongen."}'::text[], 'maximaal', 1, 1, null, 90, false, 1, 5, 'bij 5x1 explosief', 'pl2_lateral_hops', 'pl4_box_jump', 'geen', '{bilspieren,quadriceps,elasticiteit}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='plyo'), 4, 'pl4_box_jump', 'Box jump', 'Verticale explosie met een zachte landing: kracht zonder impact.', '{"Zet een stevige box of verhoging voor je op een hoogte die je zeker haalt.","Sta een halve meter ervoor, licht door de knieen."}'::text[], '{"Zwaai je armen en spring op de box, land zacht met gebogen knieen.","Sta volledig rechtop bovenop.","Stap terug naar beneden, spring nooit af."}'::text[], 'In bij het laden, uit bij de sprong.', '{"Afspringen van de box: stap altijd terug omlaag om je knieen te sparen.","Te hoge box: kies er een die je met marge haalt.","Hard landen: absorbeer met je knieen en heupen."}'::text[], 'explosief', 3, 3, null, 90, false, 3, 5, 'bij 5x3 zachte landingen', 'pl3_broad_jump', 'pl5_depth_jump', 'verhoging', '{bilspieren,quadriceps,elasticiteit}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='plyo'), 5, 'pl5_depth_jump', 'Depth drop naar depth jump', 'De echte plyometrie: opvangen en direct terugveren.', '{"Sta op een lage box (begin laag, 20-30 cm).","Zorg voor een zachte ondergrond."}'::text[], '{"Stap eraf en land zacht: dat is de depth drop, beheers eerst de landing.","Als de landing schoon is: land en spring meteen explosief omhoog (depth jump).","Minimale grondtijd, maximale terugveer."}'::text[], 'Kort en explosief ademen op de sprong.', '{"Te hoge box: begin laag, verhoog pas als de landing perfect is.","Lang op de grond: de terugveer moet direct.","Volume opstapelen: dit is zeer intensief, houd het minimaal."}'::text[], 'reactief', 3, 3, null, 120, false, 3, 5, 'lange termijn', 'pl4_box_jump', null, 'verhoging', '{bilspieren,kuiten,elasticiteit}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='mobiliteit'), 1, 'mo1_hurk_hang', 'Diepe hurk-hang', 'Zak in een diepe hurk en laat je heupen en enkels openen.', '{"Voeten iets breder dan heupbreed, tenen licht naar buiten.","Zak in een volledige hurk, hielen plat."}'::text[], '{"Laat je ellebogen je knieen zacht naar buiten duwen.","Houd je borst omhoog en ontspan in de positie.","Adem de heupen los."}'::text[], 'Diep en rustig ademen, laat je heupen zakken op elke uitademing.', '{"Hielen loskomen: leg iets onder je hielen of ga minder diep.","Ronde rug: houd je borst open."}'::text[], 'hold', null, null, 60, 0, false, null, null, 'markeer: platte hurk zonder steun', null, null, 'geen', '{heupen,enkels,onderrug}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='mobiliteit'), 2, 'mo2_90_90', '90/90 heupen', 'Wissel de rotatie in je heupen los, van binnen en buiten.', '{"Zit met een been 90 graden voor je, het andere 90 graden opzij.","Zit rechtop."}'::text[], '{"Draai beide knieen traag naar de andere kant zonder je handen.","Zoek de eindstand en houd even vast.","Wissel heen en weer."}'::text[], 'Rustig ademen, forceer niet.', '{"Voorover klappen: blijf rechtop.","Forceren voorbij je bereik: blijf net binnen comfort."}'::text[], 'hold', null, null, 60, 0, false, null, null, 'markeer: soepel wisselen zonder handen', 'mo1_hurk_hang', 'mo3_dislocates', 'geen', '{heupen}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='mobiliteit'), 3, 'mo3_dislocates', 'Schouder-dislocates', 'Open je schouders met een band of stok van voor naar achter.', '{"Pak een band of stok breed vast, armen gestrekt voor je.","Sta rechtop, romp stil."}'::text[], '{"Beweeg je gestrekte armen in een grote boog over je hoofd naar achteren.","Ga alleen zo breed als comfortabel, versmal je greep naarmate je losser wordt.","Terug naar voren, herhaal traag."}'::text[], 'In terwijl de armen omhoog gaan, uit als ze naar achteren zakken.', '{"Ellebogen buigen: houd de armen recht.","Doorbuigen in de onderrug: houd je ribben laag."}'::text[], 'hold', null, null, 45, 0, false, null, null, 'markeer: smallere greep over tijd', 'mo2_90_90', 'mo4_wall_slides', 'geen', '{schouders,borst}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='mobiliteit'), 4, 'mo4_wall_slides', 'Wall slides', 'Leer je schouderbladen goed bewegen tegen een muur.', '{"Sta met je rug, billen en hoofd tegen de muur.","Armen tegen de muur in een W-vorm, ellebogen laag."}'::text[], '{"Schuif je armen omhoog naar een Y terwijl alles tegen de muur blijft.","Kom alleen zo hoog als je contact houdt.","Schuif gecontroleerd terug naar de W."}'::text[], 'Rustig doorademen door de beweging.', '{"Onderrug van de muur: houd je ribben laag.","Polsen of ellebogen loskomen: ga minder hoog."}'::text[], 'hold', null, null, 45, 0, false, null, null, 'markeer: volledige Y met contact', 'mo3_dislocates', 'mo5_thoracale_rotatie', 'geen', '{schouders,bovenrug}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='mobiliteit'), 5, 'mo5_thoracale_rotatie', 'Thoracale rotaties', 'Draai je bovenrug los waar hij door zitten vastzet.', '{"Kom op handen en knieen, of lig op je zij met knieen opgetrokken.","Een hand achter je hoofd of voor je uit."}'::text[], '{"Draai je elleboog open naar het plafond en volg met je blik.","Beweeg vanuit je borstwervels, niet je onderrug.","Terug en herhaal, wissel van kant."}'::text[], 'Adem in bij het openen, uit onderin de rotatie.', '{"Vanuit de onderrug draaien: houd je bekken stil.","Forceren: draai net tot je eindbereik."}'::text[], 'hold', null, null, 45, 0, false, null, null, 'markeer: grotere rotatie over tijd', 'mo4_wall_slides', 'mo6_jefferson_curl', 'geen', '{bovenrug,borst}'::text[]);
insert into ladder_exercises (pattern_id, rung, slug, name, one_liner, setup, execution, breathing, mistakes, tempo, rep_low, rep_high, hold_sec, rest_sec, is_unilateral, advance_reps, advance_sets, advance_note, regression_slug, progression_slug, equipment, muscles) values ((select id from movement_patterns where key='mobiliteit'), 6, 'mo6_jefferson_curl', 'Lichte jefferson curl', 'Rol wervel voor wervel af voor sterke, soepele hamstrings en rug.', '{"Sta op een verhoging met lichte of geen belasting.","Voeten heupbreed, benen bijna gestrekt."}'::text[], '{"Rol traag af, kin naar borst, wervel voor wervel naar beneden.","Laat je armen zwaar hangen, ga tot je comfortabele eindbereik.","Rol net zo gecontroleerd weer omhoog."}'::text[], 'Adem uit terwijl je afrolt, in terwijl je omhoog rolt.', '{"Te veel gewicht: begin met alleen lichaamsgewicht.","Ploffen naar beneden: rol traag en beheerst."}'::text[], 'zeer langzaam', 5, 8, null, 0, false, null, null, 'markeer: verdere reik over tijd', 'mo5_thoracale_rotatie', null, 'verhoging', '{hamstrings,onderrug}'::text[]);
