-- Beweging-diepte (T0): seed van de ladders, templates en slots.
-- Elke trede haalt de content-checklist (setup/execution/breathing/mistakes
-- + prescriptie + advance + regressie/progressie).

-- === Patronen ===
on conflict (key) do nothing;

-- === Sessie-templates + slots ===
on conflict (key) do nothing;

select t.id, v.sort, v.slot_type,
  (select id from movement_patterns where key = v.pattern_key), v.sets, v.note
from (values
  ('kracht_a', 1, 'warmup', null, null, 'Vijf minuten ophalen + de patronen van vandaag licht'),
  ('kracht_a', 2, 'work', 'trek_vert', 4, null),
  ('kracht_a', 3, 'work', 'duw_hor', 3, null),
  ('kracht_a', 4, 'work', 'been_knie', 3, null),
  ('kracht_a', 5, 'work', 'core', 3, null),
  ('kracht_a', 6, 'finisher', 'plyo', 3, 'Optioneel, alleen als je fris bent'),
  ('kracht_a', 7, 'cooldown', null, null, 'De korte mobiliteitsroutine')
) as v(tpl_key, sort, slot_type, pattern_key, sets, note)
join session_templates t on t.key = v.tpl_key;

select t.id, v.sort, v.slot_type,
  (select id from movement_patterns where key = v.pattern_key), v.sets, v.note
from (values
  ('kracht_b', 1, 'warmup', null, null, 'Vijf minuten ophalen + de patronen van vandaag licht'),
  ('kracht_b', 2, 'work', 'duw_vert', 4, null),
  ('kracht_b', 3, 'work', 'trek_hor', 3, null),
  ('kracht_b', 4, 'work', 'been_heup', 3, null),
  ('kracht_b', 5, 'work', 'core', 3, null),
  ('kracht_b', 6, 'cooldown', null, null, 'De korte mobiliteitsroutine')
) as v(tpl_key, sort, slot_type, pattern_key, sets, note)
join session_templates t on t.key = v.tpl_key;

